// Solution
function validateHtmlTags(s) {
  let stack = [];
  let tags = s.split('<');
  for (let i = 1; i < tags.length; i++) {
    let tag = tags[i].split('>')[0];
    if (!tag.startsWith('/')) {
      stack.push(tag);
    } else {
      if (stack.length === 0 || stack.pop() !== tag.substring(1)) {
        return false;
      }
    }
  }
  return stack.length === 0;
}
